patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -1,10 +1,10 @@
 module mux_4to1(
   input [7:0] a, b, c, d,
   input [1:0] sel,
   output reg [7:0] out
 );

-  always @(sel)
+  always @(sel or a or b or c or d)
   begin
     case(sel)
       2'b00: out = a;
       2'b01: out = b;
       2'b10: out = c;

before_code:
module mux_4to1(
  input [7:0] a, b, c, d,
  input [1:0] sel,
  output reg [7:0] out
);

  always @(sel)
  begin
    case(sel)
      2'b00: out = a;
      2'b01: out = b;
      2'b10: out = c;
      2'b11: out = d;
    endcase
  end

endmodule

after_code:
module mux_4to1(
  input [7:0] a, b, c, d,
  input [1:0] sel,
  output reg [7:0] out
);

  always @(sel or a or b or c or d)
  begin
    case(sel)
      2'b00: out = a;
      2'b01: out = b;
      2'b10: out = c;
      2'b11: out = d;
    endcase
  end

endmodule
